@@ -0,0 +1,34 @@
+package recommendation
+
+// trendingCache holds at most trendingMax entries; oldest are evicted.
+const trendingMax = 256
+
+var trending = lru.New(trendingMax)
+
+// prefetchLoop refreshes the trending set every 30s. The LRU is fixed
+// size, so memory use is bounded regardless of how long it runs.
+func prefetchLoop(ctx context.Context, src TrendingSource) {
+	t := time.NewTicker(30 * time.Second)
+	defer t.Stop()
+	for {
+		select {
+		case <-ctx.Done():
+			return
+		case <-t.C:
+			items, err := src.Top(ctx, trendingMax)
+			if err != nil {
+				continue
+			}
+			for _, it := range items {
+				trending.Add(it.SKU, it)
+			}
+		}
+	}
+}
